patch:
--- a/multiplexer.v
+++ b/multiplexer.v
@@ -1,7 +1,7 @@
 module mux_4to1(
     input [7:0] data_a, data_b, data_c, data_d,
     input [1:0] sel,
     output reg [7:0] out
 );
-    always @(data_a or sel)
+    always @(data_a or data_b or data_c or data_d or sel)
         case(sel)
             2'b00: out = data_a;
             2'b01: out = data_b;

before_code:
module mux_4to1(
    input [7:0] data_a, data_b, data_c, data_d,
    input [1:0] sel,
    output reg [7:0] out
);
    always @(data_a or sel)
        case(sel)
            2'b00: out = data_a;
            2'b01: out = data_b;
            2'b10: out = data_c;
            2'b11: out = data_d;
            default: out = 8'h00;
        endcase
endmodule

after_code:
module mux_4to1(
    input [7:0] data_a, data_b, data_c, data_d,
    input [1:0] sel,
    output reg [7:0] out
);
    always @(data_a or data_b or data_c or data_d or sel)
        case(sel)
            2'b00: out = data_a;
            2'b01: out = data_b;
            2'b10: out = data_c;
            2'b11: out = data_d;
            default: out = 8'h00;
        endcase
endmodule
